import { Stagehand } from "../lib/v3";
import dotenv from "dotenv";
dotenv.config();

async function example(stagehand: Stagehand) {
  /**
   * Add your code here!
   */
  const page = stagehand.context.pages()[0];

  await page.goto("https://occupationallicensingandpermitting.mass.gov/madol/s/license-search-page");
  await new Promise(resolve => setTimeout(resolve, 5000));

  const [obs] = await stagehand.observe("all the input fields in the page with mock data"));
  // await new Promise(resolve => setTimeout(resolve, 10000));
  await stagehand.act(obs);

  // const agent = stagehand.agent({
  //   systemPrompt: "You're a helpful assistant that can control a web browser.",
