  1→// lib/v3/handlers/handlerUtils/actHandlerUtils.ts
  2→import { Protocol } from "devtools-protocol";
  3→import { Frame } from "../../understudy/frame.js";
  4→import { Locator } from "../../understudy/locator.js";
  5→import { MouseButton } from "../../types/public/locator.js";
  6→import { resolveLocatorWithHops } from "../../understudy/deepLocator.js";
  7→import type { Page } from "../../understudy/page.js";
  8→import { v3Logger } from "../../logger.js";
  9→import { SessionFileLogger } from "../../flowLogger.js";
 10→import {
 11→  StagehandClickError,
 12→  UnderstudyCommandException,
 13→} from "../../types/public/sdkErrors.js";
 14→
 15→export interface UnderstudyMethodHandlerContext {
 16→  method: string;
 17→  locator: Locator;
 18→  xpath: string;
 19→  args: ReadonlyArray<string>;
 20→  frame: Frame;
 21→  page: Page;
 22→  initialUrl: string;
 23→  domSettleTimeoutMs?: number;
 24→}
 25→
 26→// Normalize cases where the XPath is the root "/" to point to the HTML element.
 27→function normalizeRootXPath(input: string): string {
 28→  const s = String(input ?? "").trim();
 29→  if (s === "/") return "/html";
 30→  if (/^xpath=\/$/i.test(s)) return "xpath=/html";
 31→  return s;
 32→}
 33→
 34→export async function performUnderstudyMethod(
 35→  page: Page,
 36→  frame: Frame,
 37→  method: string,
 38→  rawXPath: string,
 39→  args: ReadonlyArray<unknown>,
 40→  domSettleTimeoutMs?: number,
 41→): Promise<void> {
 42→  const selectorRaw = normalizeRootXPath(rawXPath);
 43→  // Unified resolver: supports '>>' hops and XPath across iframes
 44→  const locator: Locator = await resolveLocatorWithHops(
 45→    page,
 46→    frame,
 47→    selectorRaw,
 48→  );
 49→
 50→  const initialUrl = await getFrameUrl(frame);
 51→
 52→  v3Logger({
 53→    category: "action",
 54→    message: "performing understudy method",
 55→    level: 2,
 56→    auxiliary: {
 57→      xpath: { value: selectorRaw, type: "string" },
 58→      method: { value: method, type: "string" },
 59→      url: { value: initialUrl, type: "string" },
 60→    },
 61→  });
 62→
 63→  const ctx: UnderstudyMethodHandlerContext = {
 64→    method,
 65→    locator,
 66→    xpath: selectorRaw,
 67→    args: args.map((a) => (a == null ? "" : String(a))),
 68→    frame,
 69→    page,
 70→    initialUrl,
 71→    domSettleTimeoutMs,
 72→  };
 73→
 74→  SessionFileLogger.logUnderstudyActionEvent({
 75→    actionType: `Understudy.${method}`,
 76→    target: selectorRaw,
 77→    args: Array.from(args),
 78→  });
 79→
 80→  try {
 81→    const handler = METHOD_HANDLER_MAP[method] ?? null;
 82→
 83→    if (handler) {
 84→      await handler(ctx);
 85→    } else {
 86→      // Accept a few common locator method aliases
 87→      switch (method) {
 88→        case "click":
 89→          await clickElement(ctx);
 90→          break;
 91→        case "fill":
 92→          await fillOrType(ctx);
 93→          break;
 94→        case "type":
 95→          await typeText(ctx);
 96→          break;
 97→        default:
 98→          v3Logger({
 99→            category: "action",
100→            message: "chosen method is invalid",
101→            level: 1,
102→            auxiliary: { method: { value: method, type: "string" } },
103→          });
104→          throw new UnderstudyCommandException(
105→            `Method ${method} not supported`,
106→          );
107→      }
108→    }
109→
110→    await handlePossibleNavigation("action", selectorRaw, initialUrl, frame);
111→  } catch (e) {
112→    const msg = e instanceof Error ? e.message : String(e);
113→    const stack = e instanceof Error ? e.stack : undefined;
114→    v3Logger({
115→      category: "action",
116→      message: "error performing method",
117→      level: 1,
118→      auxiliary: {
119→        error: { value: msg, type: "string" },
120→        trace: { value: stack ?? "", type: "string" },
121→        method: { value: method, type: "string" },
122→        xpath: { value: selectorRaw, type: "string" },
123→        args: { value: JSON.stringify(args), type: "object" },
124→      },
125→    });
126→    if (e instanceof UnderstudyCommandException) {
127→      throw e;
128→    }
129→    throw new UnderstudyCommandException(msg, e);
130→  } finally {
131→    SessionFileLogger.logUnderstudyActionCompleted();
132→  }
133→}
134→
135→/* ===================== Handlers & Map ===================== */
136→
137→const METHOD_HANDLER_MAP: Record<
138→  string,
139→  (ctx: UnderstudyMethodHandlerContext) => Promise<void>
140→> = {
141→  scrollIntoView,
142→  scrollByPixelOffset,
143→  scrollTo: scrollElementToPercentage,
144→  scroll: scrollElementToPercentage,
145→  "mouse.wheel": wheelScroll,
146→  fill: fillOrType,
147→  type: typeText,
148→  press: pressKey,
149→  click: clickElement,
150→  doubleClick,
151→  dragAndDrop,
152→  nextChunk: scrollToNextChunk,
153→  prevChunk: scrollToPreviousChunk,
154→  selectOptionFromDropdown: selectOption,
155→  selectOption: selectOption,
156→  hover: hover,
157→};
