159→export async function selectOption(ctx: UnderstudyMethodHandlerContext) {
160→  const { locator, xpath, args } = ctx;
161→  try {
162→    const text = args[0]?.toString() || "";
163→    await locator.selectOption(text);
164→  } catch (e) {
165→    const msg = e instanceof Error ? e.message : String(e);
166→    const stack = e instanceof Error ? e.stack : undefined;
167→    v3Logger({
168→      category: "action",
169→      message: "error selecting option",
170→      level: 0,
171→      auxiliary: {
172→        error: { value: msg, type: "string" },
173→        trace: { value: stack ?? "", type: "string" },
174→        xpath: { value: xpath, type: "string" },
175→      },
176→    });
177→    throw new UnderstudyCommandException(msg, e);
178→  }
179→}
