181→async function scrollIntoView(
182→  ctx: UnderstudyMethodHandlerContext,
183→): Promise<void> {
184→  const { locator, xpath } = ctx;
185→  v3Logger({
186→    category: "action",
187→    message: "scrolling element into view",
188→    level: 2,
189→    auxiliary: { xpath: { value: xpath, type: "string" } },
190→  });
191→  const { objectId } = await locator.resolveNode();
192→  const ownerSession = locator.getFrame().session;
193→  await ownerSession.send("DOM.scrollIntoViewIfNeeded", { objectId });
194→  await ownerSession
195→    .send("Runtime.releaseObject", { objectId })
196→    .catch(() => {});
197→}
