199→async function scrollElementToPercentage(
200→  ctx: UnderstudyMethodHandlerContext,
201→): Promise<void> {
202→  const { locator, xpath, args } = ctx;
203→  v3Logger({
204→    category: "action",
205→    message: "scrolling element vertically to specified percentage",
206→    level: 2,
207→    auxiliary: {
208→      xpath: { value: xpath, type: "string" },
209→      coordinate: { value: JSON.stringify(args), type: "string" },
210→    },
211→  });
212→
213→  const [yArg = "0%"] = args;
214→  await locator.scrollTo(yArg);
215→}
