217→/** Scroll the page by pixel offset, starting from the element's center. */
218→async function scrollByPixelOffset(
219→  ctx: UnderstudyMethodHandlerContext,
220→): Promise<void> {
221→  const { locator, page, args } = ctx;
222→  const dx = Number(args[0] ?? 0);
223→  const dy = Number(args[1] ?? 0);
224→
225→  try {
226→    const { x, y } = await locator.centroid();
227→    await page.scroll(x, y, dx, dy);
228→  } catch (e) {
229→    const msg = e instanceof Error ? e.message : String(e);
230→    throw new UnderstudyCommandException(msg, e);
231→  }
232→}
