361→async function dragAndDrop(ctx: UnderstudyMethodHandlerContext): Promise<void> {
362→  const { page, frame, locator, args, xpath } = ctx;
363→  const toXPath = String(args[0] ?? "").trim();
364→  if (!toXPath)
365→    throw new UnderstudyCommandException(
366→      "dragAndDrop requires a target XPath arg",
367→    );
368→
369→  const targetLocator = await resolveLocatorWithHops(page, frame, toXPath);
370→
371→  try {
372→    // 1) Centers in local (owning-frame) viewport
373→    const { x: fromLocalX, y: fromLocalY } = await locator.centroid();
374→    const { x: toLocalX, y: toLocalY } = await targetLocator.centroid();
375→
376→    // 2) Convert to main-viewport absolute coordinates
377→    const fromAbs = await locator
378→      .getFrame()
379→      .evaluate<{ x: number; y: number }, { x: number; y: number }>(
380→        ({ x, y }: { x: number; y: number }) => {
381→          let X = x;
382→          let Y = y;
383→          let w: Window = window;
384→          while (w !== w.top) {
385→            const fe = w.frameElement as HTMLElement | null;
386→            if (!fe) break;
387→            const r = fe.getBoundingClientRect();
388→            X += r.left;
389→            Y += r.top;
390→            w = w.parent as Window;
391→          }
392→          return { x: Math.round(X), y: Math.round(Y) };
393→        },
394→        { x: fromLocalX, y: fromLocalY },
395→      );
396→
397→    const toAbs = await targetLocator
398→      .getFrame()
399→      .evaluate<{ x: number; y: number }, { x: number; y: number }>(
400→        ({ x, y }: { x: number; y: number }) => {
401→          let X = x;
402→          let Y = y;
403→          let w: Window = window;
404→          while (w !== w.top) {
405→            const fe = w.frameElement as HTMLElement | null;
406→            if (!fe) break;
407→            const r = fe.getBoundingClientRect();
408→            X += r.left;
409→            Y += r.top;
410→            w = w.parent as Window;
411→          }
412→          return { x: Math.round(X), y: Math.round(Y) };
413→        },
414→        { x: toLocalX, y: toLocalY },
415→      );
416→
417→    // 3) Perform drag in main session
418→    await page.dragAndDrop(fromAbs.x, fromAbs.y, toAbs.x, toAbs.y, {
419→      steps: 10,
420→      delay: 5,
421→    });
422→  } catch (e) {
423→    const msg = e instanceof Error ? e.message : String(e);
424→    v3Logger({
425→      category: "action",
426→      message: "error performing dragAndDrop",
427→      level: 0,
428→      auxiliary: {
429→        error: { value: msg, type: "string" },
430→        from: { value: xpath, type: "string" },
431→        to: { value: toXPath, type: "string" },
432→      },
433→    });
434→    throw new UnderstudyCommandException(msg, e);
435→  }
436→}
