450→async function scrollByElementHeight(
451→  ctx: UnderstudyMethodHandlerContext,
452→  direction: 1 | -1,
453→): Promise<void> {
454→  const { locator, xpath } = ctx;
455→  v3Logger({
456→    category: "action",
457→    message:
458→      direction > 0 ? "scrolling to next chunk" : "scrolling to previous chunk",
459→    level: 2,
460→    auxiliary: { xpath: { value: xpath, type: "string" } },
461→  });
462→
463→  const { objectId } = await locator.resolveNode();
464→  try {
465→    const ownerSession = locator.getFrame().session;
466→    await ownerSession.send<Protocol.Runtime.CallFunctionOnResponse>(
467→      "Runtime.callFunctionOn",
468→      {
469→        objectId,
470→        functionDeclaration: `
471→          function(dir) {
472→            const waitForScrollEnd = (el) => new Promise((resolve) => {
473→              let last = el.scrollTop ?? 0;
474→              const check = () => {
475→                const cur = el.scrollTop ?? 0;
476→                if (cur === last) return resolve();
477→                last = cur;
478→                requestAnimationFrame(check);
479→              };
480→              requestAnimationFrame(check);
481→            });
482→
483→            const tag = this.tagName?.toLowerCase();
484→            if (tag === "html" || tag === "body") {
485→              const h = window.visualViewport?.height ?? window.innerHeight;
486→              window.scrollBy({ top: h * dir, left: 0, behavior: "smooth" });
487→              const root = document.scrollingElement ?? document.documentElement;
488→              return waitForScrollEnd(root);
489→            }
490→            const h = this.getBoundingClientRect().height;
491→            this.scrollBy({ top: h * dir, left: 0, behavior: "smooth" });
492→            return waitForScrollEnd(this);
493→          }
494→        `,
495→        arguments: [{ value: direction }],
496→        awaitPromise: true,
497→        returnByValue: true,
498→      },
499→    );
500→  } finally {
501→    const ownerSession = locator.getFrame().session;
502→    await ownerSession
503→      .send("Runtime.releaseObject", { objectId })
504→      .catch(() => {});
505→  }
506→}
