537→/**
538→ * More robust DOM settle using Network + Page events to detect network quiet.
539→ * Closely modeled after the provided snippet, adapted to our Frame/session + logger.
540→ */
541→export async function waitForDomNetworkQuiet(
542→  frame: Frame,
543→  timeoutMs?: number,
544→): Promise<void> {
545→  const overallTimeout =
546→    typeof timeoutMs === "number" && Number.isFinite(timeoutMs)
547→      ? Math.max(0, timeoutMs)
548→      : 5_000;
549→  const client = frame.session;
550→  const settleStart = Date.now();
551→
552→  // Ensure a document exists; if not, wait for DOMContentLoaded on this frame.
553→  let hasDoc: boolean;
554→  try {
555→    const rs = await frame.evaluate<string>("document.readyState");
556→    hasDoc = rs === "interactive" || rs === "complete";
557→  } catch {
558→    hasDoc = false;
559→  }
560→  if (!hasDoc && overallTimeout > 0) {
561→    await frame
562→      .waitForLoadState("domcontentloaded", overallTimeout)
563→      .catch(() => {});
564→  }
565→
566→  const elapsed = Date.now() - settleStart;
567→  const remainingBudget = Math.max(0, overallTimeout - elapsed);
568→  if (remainingBudget === 0) {
569→    return;
570→  }
571→
572→  await client.send("Network.enable").catch(() => {});
573→  await client.send("Page.enable").catch(() => {});
574→  // Best-effort; some sessions may not support Target.setAutoAttach here.
575→  await client
576→    .send("Target.setAutoAttach", {
577→      autoAttach: true,
578→      waitForDebuggerOnStart: false,
579→      flatten: true,
580→      filter: [
581→        { type: "worker", exclude: true },
582→        { type: "shared_worker", exclude: true },
583→      ],
584→    })
585→    .catch(() => {});
586→
587→  return new Promise<void>((resolve) => {
588→    const inflight = new Set<string>();
589→    const meta = new Map<string, { url: string; start: number }>();
590→    const docByFrame = new Map<string, string>();
591→
592→    let quietTimer: NodeJS.Timeout | null = null;
593→    let stalledRequestSweepTimer: NodeJS.Timeout | null = null;
594→
595→    const clearQuiet = () => {
596→      if (quietTimer) {
597→        clearTimeout(quietTimer);
598→        quietTimer = null;
599→      }
600→    };
601→
602→    const maybeQuiet = () => {
603→      if (inflight.size === 0 && !quietTimer)
604→        quietTimer = setTimeout(() => resolveDone(), 500);
605→    };
606→
607→    const finishReq = (id: string) => {
608→      if (!inflight.delete(id)) return;
609→      meta.delete(id);
610→      for (const [fid, rid] of docByFrame)
611→        if (rid === id) docByFrame.delete(fid);
612→      clearQuiet();
613→      maybeQuiet();
614→    };
615→
616→    const onRequest = (p: Protocol.Network.RequestWillBeSentEvent) => {
617→      // Ignore long-lived streams
618→      // ResourceType includes: Document, XHR, Fetch, WebSocket, EventSource, etc.
619→      if (p.type === "WebSocket" || p.type === "EventSource") return;
620→
621→      inflight.add(p.requestId);
622→      meta.set(p.requestId, { url: p.request.url, start: Date.now() });
623→
624→      if (p.type === "Document" && p.frameId)
625→        docByFrame.set(p.frameId, p.requestId);
626→
627→      clearQuiet();
628→    };
629→
630→    const onFinish = (p: { requestId: string }) => finishReq(p.requestId);
631→    const onCached = (p: { requestId: string }) => finishReq(p.requestId);
632→    const onDataUrl = (p: Protocol.Network.ResponseReceivedEvent) => {
633→      if (p.response.url?.startsWith("data:")) finishReq(p.requestId);
634→    };
635→
636→    const onFrameStop = (f: Protocol.Page.FrameStoppedLoadingEvent) => {
637→      const id = docByFrame.get(f.frameId);
638→      if (id) finishReq(id);
639→    };
640→
641→    client.on("Network.requestWillBeSent", onRequest);
642→    client.on("Network.loadingFinished", onFinish);
643→    client.on("Network.loadingFailed", onFinish);
644→    client.on("Network.requestServedFromCache", onCached);
645→    client.on("Network.responseReceived", onDataUrl);
646→    client.on("Page.frameStoppedLoading", onFrameStop);
647→
648→    stalledRequestSweepTimer = setInterval(() => {
649→      const now = Date.now();
650→      for (const [id, m] of meta) {
651→        if (now - m.start > 2_000) {
652→          inflight.delete(id);
653→          meta.delete(id);
654→          v3Logger({
655→            category: "dom",
656→            message: "⏳ forcing completion of stalled iframe document",
657→            level: 1,
658→            auxiliary: {
659→              url: { value: (m.url ?? "").slice(0, 120), type: "string" },
660→            },
661→          });
662→        }
663→      }
664→      maybeQuiet();
665→    }, 500);
666→
667→    maybeQuiet();
668→
669→    const guard = setTimeout(() => {
670→      if (inflight.size) {
671→        v3Logger({
672→          category: "dom",
673→          message:
674→            "⚠️ DOM-settle timeout reached – network requests still pending",
675→          level: 1,
676→          auxiliary: {
677→            count: { value: String(inflight.size), type: "integer" },
678→          },
679→        });
680→      }
681→      resolveDone();
682→    }, remainingBudget);
683→
684→    const resolveDone = () => {
685→      client.off("Network.requestWillBeSent", onRequest);
686→      client.off("Network.loadingFinished", onFinish);
687→      client.off("Network.loadingFailed", onFinish);
688→      client.off("Network.requestServedFromCache", onCached);
689→      client.off("Network.responseReceived", onDataUrl);
690→      client.off("Page.frameStoppedLoading", onFrameStop);
691→      if (quietTimer) clearTimeout(quietTimer);
692→      if (stalledRequestSweepTimer) clearInterval(stalledRequestSweepTimer);
693→      clearTimeout(guard);
694→      resolve();
695→    };
696→  });
697→}
