  8→/**
  9→ * Recognize iframe steps like "iframe" or "iframe[2]" in an XPath.
 10→ */
 11→const IFRAME_STEP_RE = /^iframe(?:\[\d+])?$/i;
 12→
 13→type Axis = "child" | "desc";
 14→type Step = { axis: Axis; raw: string; name: string };
 15→
 16→export type ResolvedLocatorTarget = {
 17→  frame: Frame;
 18→  selector: string;
 19→};
 20→
 21→/** Parse XPath into steps preserving '/' vs '//' and the raw token (with [n]) */
 22→function parseXPath(path: string): Step[] {
 23→  const s = path.trim();
 24→  let i = 0;
 25→  const steps: Step[] = [];
 26→  while (i < s.length) {
 27→    let axis: Axis = "child";
 28→    if (s.startsWith("//", i)) {
 29→      axis = "desc";
 30→      i += 2;
 31→    } else if (s[i] === "/") {
 32→      axis = "child";
 33→      i += 1;
 34→    }
 35→
 36→    const start = i;
 37→    while (i < s.length && s[i] !== "/") i++;
 38→    const raw = s.slice(start, i).trim();
 39→    if (!raw) continue;
 40→
 41→    const name = raw.replace(/\[\d+\]\s*$/u, "").toLowerCase();
 42→    steps.push({ axis, raw, name });
 43→  }
 44→  return steps;
 45→}
 46→
 47→function buildXPathFromSteps(steps: ReadonlyArray<Step>): string {
 48→  let out = "";
 49→  for (const st of steps) {
 50→    out += st.axis === "desc" ? "//" : "/";
 51→    out += st.raw; // keep predicates intact
 52→  }
 53→  return out || "/";
 54→}
