 56→/** Build a Locator scoped to the correct frame for a deep XPath crossing iframes. */
 57→export async function deepLocatorThroughIframes(
 58→  page: Page,
 59→  root: Frame,
 60→  xpathOrSelector: string,
 61→): Promise<Locator> {
 62→  const target = await resolveDeepXPathTarget(page, root, xpathOrSelector);
 63→  return new Locator(target.frame, target.selector);
