 66→/**
 67→ * Unified resolver that supports '>>' hop notation, deep XPath across iframes,
 68→ * and plain single-frame selectors. Keeps hop logic in one shared place.
 69→ */
 70→export async function resolveLocatorTarget(
 71→  page: Page,
 72→  root: Frame,
 73→  selectorRaw: string,
 74→): Promise<ResolvedLocatorTarget> {
 75→  const sel = selectorRaw.trim();
 76→  const parts = sel
 77→    .split(">>")
 78→    .map((s) => s.trim())
 79→    .filter(Boolean);
 80→
 81→  if (parts.length > 1) {
 82→    // Build a FrameLocator chain for all but the last segment
 83→    let fl = frameLocatorFromFrame(page, root, parts[0]!);
 84→    for (let i = 1; i < parts.length - 1; i++) {
 85→      fl = fl.frameLocator(parts[i]!);
 86→    }
 87→    const targetFrame = await fl.resolveFrame();
 88→    return { frame: targetFrame, selector: parts[parts.length - 1]! };
 89→  }
 90→
 91→  // No hops — delegate to XPath-aware deep resolver when needed
 92→  const isXPath = sel.startsWith("xpath=") || sel.startsWith("/");
 93→  if (isXPath) {
 94→    return resolveDeepXPathTarget(page, root, sel);
 95→  }
 96→  return { frame: root, selector: sel };
 97→}
