 99→export async function resolveLocatorWithHops(
100→  page: Page,
101→  root: Frame,
102→  selectorRaw: string,
103→): Promise<Locator> {
104→  const target = await resolveLocatorTarget(page, root, selectorRaw);
105→  return new Locator(target.frame, target.selector);
