244→
245→async function resolveDeepXPathTarget(
246→  page: Page,
247→  root: Frame,
248→  xpathOrSelector: string,
249→): Promise<ResolvedLocatorTarget> {
250→  let path = xpathOrSelector.trim();
251→  if (path.startsWith("xpath=")) path = path.slice("xpath=".length).trim();
252→  if (!path.startsWith("/")) path = "/" + path;
253→
254→  const steps = parseXPath(path);
255→  let fl: FrameLocator | undefined;
256→  let buf: Step[] = [];
257→
258→  const flushIntoFrameLocator = () => {
259→    if (!buf.length) return;
260→    const selectorForIframe = "xpath=" + buildXPathFromSteps(buf);
261→    v3Logger({
262→      category: "deep-hop",
263→      message: "resolving iframe via FrameLocator",
264→      level: 2,
265→      auxiliary: {
266→        selectorForIframe: { value: selectorForIframe, type: "string" },
267→        rootFrameId: { value: String(root.frameId), type: "string" },
268→      },
269→    });
270→    fl = fl
271→      ? fl.frameLocator(selectorForIframe)
272→      : frameLocatorFromFrame(page, root, selectorForIframe);
273→    buf = [];
274→  };
275→
276→  for (const st of steps) {
277→    buf.push(st);
278→    if (IFRAME_STEP_RE.test(st.name)) flushIntoFrameLocator();
279→  }
280→
281→  const finalSelector = "xpath=" + buildXPathFromSteps(buf);
282→  const targetFrame = fl ? await fl.resolveFrame() : root;
283→  v3Logger({
284→    category: "deep-hop",
285→    message: "final tail",
286→    level: 2,
287→    auxiliary: {
288→      frameId: { value: String(targetFrame.frameId), type: "string" },
289→      finalSelector: { value: finalSelector, type: "string" },
290→    },
291→  });
292→  return { frame: targetFrame, selector: finalSelector };
293→}
