  6→
  7→type ClosedRootGetter = (host: Element) => ShadowRoot | null;
  8→
  9→export type XPathResolveOptions = {
 10→  pierceShadow?: boolean;
 11→};
 12→
 13→type ShadowContext = {
 14→  getClosedRoot: ClosedRootGetter | null;
 15→  hasShadow: boolean;
 16→};
 17→
 18→const normalizeXPath = (selector: string): string => {
 19→  const raw = String(selector ?? "").trim();
 20→  if (!raw) return "";
 21→  return raw.replace(/^xpath=/i, "").trim();
 22→};
 23→
 24→export function resolveXPathFirst(
 25→  rawXp: string,
 26→  options?: XPathResolveOptions,
 27→): Element | null {
 28→  return resolveXPathAtIndex(rawXp, 0, options);
 29→}
 30→
 31→export function resolveXPathAtIndex(
 32→  rawXp: string,
 33→  index: number,
 34→  options?: XPathResolveOptions,
 35→): Element | null {
 36→  if (!Number.isFinite(index) || index < 0) return null;
 37→  const xp = normalizeXPath(rawXp);
 38→  if (!xp) return null;
 39→
 40→  const targetIndex = Math.floor(index);
 41→  const pierceShadow = options?.pierceShadow !== false;
 42→  const shadowCtx = pierceShadow ? getShadowContext() : null;
 43→
 44→  if (!pierceShadow) {
 45→    return resolveNativeAtIndexWithError(xp, targetIndex).value;
 46→  }
 47→
 48→  if (!shadowCtx?.hasShadow) {
 49→    const native = resolveNativeAtIndexWithError(xp, targetIndex);
 50→    if (!native.error) return native.value;
 51→    const composed = resolveXPathComposedMatches(xp, shadowCtx?.getClosedRoot);
 52→    return composed[targetIndex] ?? null;
 53→  }
 54→
 55→  const composed = resolveXPathComposedMatches(xp, shadowCtx.getClosedRoot);
 56→  return composed[targetIndex] ?? null;
 57→}
 58→
 59→export function countXPathMatches(
 60→  rawXp: string,
 61→  options?: XPathResolveOptions,
 62→): number {
 63→  const xp = normalizeXPath(rawXp);
 64→  if (!xp) return 0;
 65→
 66→  const pierceShadow = options?.pierceShadow !== false;
 67→  const shadowCtx = pierceShadow ? getShadowContext() : null;
 68→
 69→  if (!pierceShadow) {
 70→    return resolveNativeCountWithError(xp).count;
 71→  }
 72→
 73→  if (!shadowCtx?.hasShadow) {
 74→    const count = resolveNativeCountWithError(xp);
 75→    if (!count.error) return count.count;
 76→    return resolveXPathComposedMatches(xp, shadowCtx?.getClosedRoot).length;
 77→  }
 78→
 79→  return resolveXPathComposedMatches(xp, shadowCtx.getClosedRoot).length;
 80→}
 81→
 82→export function resolveXPathComposedMatches(
 83→  rawXp: string,
 84→  getClosedRoot?: ClosedRootGetter | null,
 85→): Element[] {
 86→  const xp = normalizeXPath(rawXp);
 87→  if (!xp) return [];
 88→
 89→  const steps = parseXPathSteps(xp);
 90→  if (!steps.length) return [];
 91→
 92→  const closedRoot = getClosedRoot ?? null;
 93→
 94→  let current: Array<Document | Element | ShadowRoot | DocumentFragment> = [
 95→    document,
 96→  ];
 97→
 98→  for (const step of steps) {
 99→    const next: Element[] = [];
100→    const seen = new Set<Element>();
101→
102→    for (const root of current) {
103→      if (!root) continue;
104→      const pool =
105→        step.axis === "child"
106→          ? composedChildren(root, closedRoot)
107→          : composedDescendants(root, closedRoot);
108→      if (!pool.length) continue;
109→
110→      const tagMatches = pool.filter((candidate) =>
111→        matchesTag(candidate, step),
112→      );
113→      const matches = applyPredicates(tagMatches, step.predicates);
114→
115→      for (const candidate of matches) {
116→        if (!seen.has(candidate)) {
117→          seen.add(candidate);
118→          next.push(candidate);
119→        }
120→      }
121→    }
122→
123→    if (!next.length) return [];
124→    current = next;
125→  }
126→
127→  return current as Element[];
128→}
129→
130→function matchesTag(element: Element, step: XPathStep): boolean {
131→  if (step.tag === "*") return true;
132→  return element.localName === step.tag;
133→}
134→
135→function getShadowContext(): ShadowContext {
136→  const backdoor = window.__stagehandV3__;
137→  const getClosedRoot: ClosedRootGetter | null =
138→    backdoor && typeof backdoor.getClosedRoot === "function"
139→      ? (host: Element): ShadowRoot | null => {
140→          try {
141→            return backdoor.getClosedRoot(host) ?? null;
142→          } catch {
143→            return null;
144→          }
145→        }
146→      : null;
147→
148→  let hasShadow = false;
149→  try {
150→    if (backdoor && typeof backdoor.stats === "function") {
151→      const stats = backdoor.stats();
152→      hasShadow = (stats?.open ?? 0) > 0 || (stats?.closed ?? 0) > 0;
153→    }
154→  } catch {
155→    // ignore stats errors
156→  }
157→
158→  if (!hasShadow) {
159→    try {
160→      const walker = document.createTreeWalker(
161→        document,
162→        NodeFilter.SHOW_ELEMENT,
163→      );
164→      while (walker.nextNode()) {
165→        const el = walker.currentNode as Element;
166→        if (el.shadowRoot) {
167→          hasShadow = true;
168→          break;
169→        }
170→      }
171→    } catch {
172→      // ignore scan errors
173→    }
174→  }
175→
176→  return { getClosedRoot, hasShadow };
177→}
178→
179→function composedChildren(
180→  node: Node | null | undefined,
181→  getClosedRoot: ClosedRootGetter | null,
182→): Element[] {
183→  const out: Element[] = [];
184→  if (!node) return out;
185→
186→  if (node instanceof Document) {
187→    if (node.documentElement) out.push(node.documentElement);
188→    return out;
189→  }
190→
191→  if (node instanceof ShadowRoot || node instanceof DocumentFragment) {
192→    out.push(...Array.from(node.children ?? []));
193→    return out;
194→  }
195→
196→  if (node instanceof Element) {
197→    out.push(...Array.from(node.children ?? []));
198→    const open = node.shadowRoot;
199→    if (open) out.push(...Array.from(open.children ?? []));
200→    if (getClosedRoot) {
201→      const closed = getClosedRoot(node);
202→      if (closed) out.push(...Array.from(closed.children ?? []));
203→    }
204→    return out;
205→  }
206→
207→  return out;
208→}
209→
210→function composedDescendants(
211→  node: Node | null | undefined,
212→  getClosedRoot: ClosedRootGetter | null,
213→): Element[] {
214→  const out: Element[] = [];
215→  const seen = new Set<Element>();
216→  const stack = [...composedChildren(node, getClosedRoot)].reverse();
217→
218→  while (stack.length) {
219→    const next = stack.pop();
220→    if (!next || seen.has(next)) continue;
221→    seen.add(next);
222→    out.push(next);
223→
224→    const children = composedChildren(next, getClosedRoot);
225→    for (let i = children.length - 1; i >= 0; i -= 1) {
226→      stack.push(children[i]!);
227→    }
228→  }
229→
230→  return out;
231→}
232→
233→function resolveNativeAtIndexWithError(
234→  xp: string,
235→  index: number,
236→): { value: Element | null; error: boolean } {
237→  try {
238→    const snapshot = document.evaluate(
239→      xp,
240→      document,
241→      null,
242→      XPathResult.ORDERED_NODE_SNAPSHOT_TYPE,
243→      null,
244→    );
245→    return {
246→      value: snapshot.snapshotItem(index) as Element | null,
247→      error: false,
248→    };
249→  } catch {
250→    return { value: null, error: true };
251→  }
252→}
253→
254→function resolveNativeCountWithError(xp: string): {
255→  count: number;
256→  error: boolean;
257→} {
258→  try {
259→    const snapshot = document.evaluate(
260→      xp,
261→      document,
262→      null,
263→      XPathResult.ORDERED_NODE_SNAPSHOT_TYPE,
264→      null,
265→    );
266→    return { count: snapshot.snapshotLength, error: false };
267→  } catch {
268→    return { count: 0, error: true };
269→  }
270→}
