  1→export interface V3ShadowPatchOptions {
  2→  debug?: boolean;
  3→  tagExisting?: boolean;
  4→}
  5→
  6→export interface StagehandV3Backdoor {
  7→  /** Closed shadow-root accessors */
  8→  getClosedRoot(host: Element): ShadowRoot | undefined;
  9→  /** Stats + quick health check */
 10→  stats(): {
 11→    installed: true;
 12→    url: string;
 13→    isTop: boolean;
 14→    open: number;
 15→    closed: number;
 16→  };
 17→}
 18→
 19→type V3InternalState = {
 20→  hostToRoot: WeakMap<Element, ShadowRoot>;
 21→  openCount: number;
 22→  closedCount: number;
 23→  debug: boolean;
 24→};
 25→
 26→declare global {
 27→  interface Window {
 28→    __stagehandV3Injected?: boolean;
 29→    __stagehandV3__?: StagehandV3Backdoor;
 30→  }
 31→}
 32→
 33→export function installV3ShadowPiercer(opts: V3ShadowPatchOptions = {}): void {
 34→  // hardcoded debug (remove later if desired)
 35→  const DEBUG = true;
 36→
 37→  type PatchedFn = Element["attachShadow"] & {
 38→    __v3Patched?: boolean;
 39→    __v3State?: V3InternalState;
 40→  };
 41→
 42→  const bindBackdoor = (state: V3InternalState): void => {
 43→    const { hostToRoot } = state;
 44→
 45→    window.__stagehandV3__ = {
 46→      getClosedRoot: (host: Element) => hostToRoot.get(host),
 47→      stats: () => ({
 48→        installed: true,
 49→        url: location.href,
 50→        isTop: window.top === window,
 51→        open: state.openCount,
 52→        closed: state.closedCount,
 53→      }),
 54→    } satisfies StagehandV3Backdoor;
 55→  };
 56→
 57→  // Look at the *current* function on the prototype. If it's already our patched
 58→  // function, reuse its shared state and rebind the backdoor (no new WeakMap).
 59→  const currentFn = Element.prototype.attachShadow as PatchedFn;
 60→  if (currentFn.__v3Patched && currentFn.__v3State) {
 61→    currentFn.__v3State.debug = DEBUG; // keep debug toggle consistent
 62→    bindBackdoor(currentFn.__v3State);
 63→    // idempotent: do not log "installed" again
 64→    return;
 65→  }
 66→
 67→  // First-time install: create shared state and replace the prototype method
 68→  const state: V3InternalState = {
 69→    hostToRoot: new WeakMap<Element, ShadowRoot>(),
 70→    openCount: 0,
 71→    closedCount: 0,
 72→    debug: DEBUG,
 73→  };
 74→
 75→  const original = currentFn; // keep a reference to call through
 76→  const patched: PatchedFn = function (
 77→    this: Element,
 78→    init: ShadowRootInit,
 79→  ): ShadowRoot {
 80→    const mode = init?.mode ?? "open";
 81→    const root = original.call(this, init);
 82→    try {
 83→      state.hostToRoot.set(this, root);
 84→      if (mode === "closed") state.closedCount++;
 85→      else state.openCount++;
 86→      if (state.debug) {
 87→        console.info("[v3-piercer] attachShadow", {
 88→          tag: (this as Element).tagName?.toLowerCase() ?? "",
 89→          mode,
 90→          url: location.href,
 91→        });
 92→      }
 93→    } catch {
 94→      //
 95→    }
 96→    return root;
 97→  } as PatchedFn;
 98→
 99→  // Mark the *patched* function with metadata so re-entry sees it
100→  patched.__v3Patched = true;
101→  patched.__v3State = state;
102→
103→  Object.defineProperty(Element.prototype, "attachShadow", {
104→    configurable: true,
105→    writable: true,
106→    value: patched,
107→  });
108→
109→  // Optionally tag existing open roots (closed cannot be discovered post-hoc)
110→  if (opts.tagExisting) {
111→    try {
112→      const walker = document.createTreeWalker(
113→        document,
114→        NodeFilter.SHOW_ELEMENT,
115→      );
116→      while (walker.nextNode()) {
117→        const el = walker.currentNode as Element;
118→        if (el.shadowRoot) {
119→          state.hostToRoot.set(el, el.shadowRoot);
120→          state.openCount++;
121→        }
122→      }
123→    } catch {
124→      //
125→    }
126→  }
127→
128→  window.__stagehandV3Injected = true;
129→  bindBackdoor(state);
130→
131→  if (state.debug) {
132→    console.info("[v3-piercer] installed", {
133→      url: location.href,
134→      isTop: window.top === window,
135→      readyState: document.readyState,
136→    });
137→  }
138→}
