 28→/**
 29→ * Locator
 30→ *
 31→ * Purpose:
 32→ * A small, CDP-based element interaction helper scoped to a specific `Frame`.
 33→ * It resolves a CSS/XPath selector inside the frame’s **isolated world**, and then
 34→ * performs low-level actions (click, type, select) using DOM/Runtime/Input
 35→ * protocol domains with minimal abstraction.
 36→ *
 37→ * Key change:
 38→ * - Prefer **objectId**-based CDP calls (scroll, geometry) to avoid brittle
 39→ *   frontend nodeId mappings. nodeId is resolved on a best-effort basis and
 40→ *   returned for compatibility, but actions do not depend on it.
 41→ *
 42→ * Notes:
 43→ * - Resolution is lazy: every action resolves the selector again.
 44→ * - Uses `Page.createIsolatedWorld` so evaluation is isolated from page scripts.
 45→ * - Releases remote objects (`Runtime.releaseObject`) where appropriate.
 46→ */
 47→export class Locator {
 48→  private readonly selectorResolver: FrameSelectorResolver;
 49→
 50→  private readonly selectorQuery: SelectorQuery;
 51→
 52→  // -1 means "no explicit nth()"; default locator resolves to first match for actions.
 53→  private readonly nthIndex: number;
 54→
 55→  constructor(
 56→    private readonly frame: Frame,
 57→    private readonly selector: string,
 58→    private readonly options?: { deep?: boolean; depth?: number },
 59→    nthIndex: number = -1,
 60→  ) {
 61→    this.selectorResolver = new FrameSelectorResolver(this.frame);
 62→    this.selectorQuery = FrameSelectorResolver.parseSelector(selector);
 63→    const normalized = Number.isFinite(nthIndex) ? Math.floor(nthIndex) : -1;
 64→    this.nthIndex = normalized < 0 ? -1 : normalized;
 65→  }
 66→
 67→  /** Return the owning Frame for this locator (typed accessor, no private access). */
 68→  public getFrame(): Frame {
 69→    return this.frame;
 70→  }
 71→
 72→  /**
 73→   * Set files on an <input type="file"> element.
 74→   *
 75→   * Mirrors Playwright's Locator.setInputFiles basics:
 76→   * - Accepts file path(s) or payload object(s) { name, mimeType, buffer }.
 77→   * - Uses CDP DOM.setFileInputFiles under the hood.
 78→   * - Best‑effort dispatches change/input via CDP (Chrome does by default).
 79→   * - Passing an empty array clears the selection.
 80→   */
 81→  public async setInputFiles(files: SetInputFilesArgument): Promise<void> {
 82→    const session = this.frame.session;
 83→    const { objectId } = await this.resolveNode();
 84→
 85→    const tempFiles: string[] = [];
 86→
 87→    try {
 88→      // Validate element is an <input type="file">
 89→      try {
 90→        const res = await session.send<Protocol.Runtime.CallFunctionOnResponse>(
 91→          "Runtime.callFunctionOn",
 92→          {
 93→            objectId,
 94→            functionDeclaration: locatorScriptSources.ensureFileInputElement,
 95→            returnByValue: true,
 96→          },
 97→        );
 98→        const ok = Boolean(res.result.value);
 99→        if (!ok)
100→          throw new StagehandInvalidArgumentError(
101→            'Target is not an <input type="file"> element',
102→          );
103→      } catch (e) {
104→        throw new StagehandInvalidArgumentError(
105→          e instanceof Error
106→            ? e.message
107→            : "Unable to verify file input element",
108→        );
109→      }
110→
111→      const normalized = await normalizeInputFiles(files);
112→
113→      if (!normalized.length) {
114→        await session.send<never>("DOM.setFileInputFiles", {
115→          objectId,
116→          files: [],
117→        });
118→        return;
119→      }
120→
121→      if (this.frame.isBrowserRemote()) {
122→        await this.assignFilesViaPayloadInjection(objectId, normalized);
123→        return;
124→      }
125→
126→      const filePaths: string[] = [];
127→      for (const payload of normalized) {
128→        if (payload.absolutePath) {
129→          filePaths.push(payload.absolutePath);
130→          continue;
131→        }
132→        const ext = path.extname(payload.name);
133→        const tmp = path.join(
134→          os.tmpdir(),
135→          `stagehand-upload-${Date.now()}-${Math.random().toString(36).slice(2)}${ext}`,
136→        );
137→        await fs.promises.writeFile(tmp, payload.buffer);
138→        tempFiles.push(tmp);
139→        filePaths.push(tmp);
140→      }
141→
142→      await session.send<never>("DOM.setFileInputFiles", {
143→        objectId,
144→        files: filePaths,
145→      });
146→    } finally {
147→      // Cleanup: release element and remove any temporary files we created
148→      await session
149→        .send<never>("Runtime.releaseObject", { objectId })
150→        .catch(() => {});
151→      for (const p of tempFiles) {
152→        try {
153→          await fs.promises.unlink(p);
154→        } catch {
155→          // ignore
156→        }
157→      }
158→    }
159→  }
