161→  /**
162→   * Remote browser fallback: build File objects inside the page and attach them via JS.
163→   *
164→   * When Stagehand is driving a browser that cannot see the local filesystem (Browserbase,
165→   * remote CDP, etc.), CDP's DOM.setFileInputFiles would fail because Chrome can't reach
166→   * our temp files. Instead we base64-encode the payloads, send them into the page, and
167→   * let a DOM helper create File objects + dispatch change/input events.
168→   */
169→  private async assignFilesViaPayloadInjection(
170→    objectId: Protocol.Runtime.RemoteObjectId,
171→    files: NormalizedFilePayload[],
172→  ): Promise<void> {
173→    const session = this.frame.session;
174→
175→    for (const payload of files) {
176→      if (payload.buffer.length > MAX_REMOTE_UPLOAD_BYTES) {
177→        throw new StagehandInvalidArgumentError(
178→          `setInputFiles(): file "${payload.name}" is larger than the 50MB limit for remote uploads`,
179→        );
180→      }
181→    }
182→
183→    const serialized = files.map((payload) => ({
184→      name: payload.name,
185→      mimeType: payload.mimeType,
186→      lastModified: payload.lastModified,
187→      base64: payload.buffer.toString("base64"),
188→    }));
189→
190→    const res = await session.send<Protocol.Runtime.CallFunctionOnResponse>(
191→      "Runtime.callFunctionOn",
192→      {
193→        objectId,
194→        functionDeclaration:
195→          locatorScriptSources.assignFilePayloadsToInputElement,
196→        arguments: [
197→          {
198→            value: serialized,
199→          },
200→        ],

 1→export function rerenderMissingShadowHosts(): void {
 2→  try {
 3→    const piercer = window.__stagehandV3__;
 4→    if (!piercer || typeof piercer.getClosedRoot !== "function") return;
 5→
 6→    const needsReset: Element[] = [];
 7→    const walker = document.createTreeWalker(document, NodeFilter.SHOW_ELEMENT);
 8→    while (walker.nextNode()) {
 9→      const el = walker.currentNode as Element;
10→      const tag = el.tagName?.toLowerCase() ?? "";
11→      if (!tag.includes("-")) continue;
12→      if (typeof customElements?.get !== "function") continue;
13→      if (!customElements.get(tag)) continue;
14→      const hasOpen = !!el.shadowRoot;
15→      const hasClosed = !!piercer.getClosedRoot(el);
16→      if (hasOpen || hasClosed) continue;
17→      needsReset.push(el);
18→    }
19→
20→    for (const host of needsReset) {
21→      try {
22→        const tag = host.tagName.toLowerCase();
23→        // createElement triggers the constructor → attachShadow() → piercer intercepts
24→        const fresh = document.createElement(tag);
25→
26→        // Transfer attributes
27→        for (const attr of Array.from(host.attributes)) {
28→          try {
29→            fresh.setAttribute(attr.name, attr.value);
30→          } catch {
31→            /* skip */
32→          }
33→        }
34→
35→        // Move light DOM children (preserves event listeners on children)
36→        while (host.firstChild) {
37→          fresh.appendChild(host.firstChild);
38→        }
39→
40→        host.replaceWith(fresh);
41→      } catch {
42→        // ignore individual failures (e.g., constructor throws)
43→      }
44→    }
45→
46→    if (piercer.stats && needsReset.length) {
47→      console.info("[v3-piercer] rerender", { count: needsReset.length });
48→    }
49→  } catch (err) {
50→    console.info("[v3-piercer] rerender error", { message: String(err ?? "") });
51→  }
52→}
