267→  /**
268→   * Highlight the element's bounding box using the CDP Overlay domain.
269→   * - Scrolls element into view best-effort.
270→   * - Shows a semi-transparent overlay briefly, then hides it.
271→   */
272→  public async highlight(options?: {
273→    durationMs?: number;
274→    borderColor?: { r: number; g: number; b: number; a?: number };
275→    contentColor?: { r: number; g: number; b: number; a?: number };
276→  }): Promise<void> {
277→    const session = this.frame.session;
278→    const { objectId } = await this.resolveNode();
279→    const duration = Math.max(0, options?.durationMs ?? 800);
280→
281→    const borderColor = options?.borderColor ?? { r: 255, g: 0, b: 0, a: 0.9 };
282→    const contentColor =
283→      options?.contentColor ?? ({ r: 255, g: 200, b: 0, a: 0.2 } as const);
284→
285→    try {
286→      await session.send("Overlay.enable").catch(() => {});
287→      await session
288→        .send("DOM.scrollIntoViewIfNeeded", { objectId })
289→        .catch(() => {});
290→
291→      // Prefer backendNodeId to keep highlight stable even if objectId is released.
292→      await session.send("DOM.enable").catch(() => {});
293→      let backendNodeId: Protocol.DOM.BackendNodeId | undefined;
294→      try {
295→        const { node } = await session.send<{ node: Protocol.DOM.Node }>(
296→          "DOM.describeNode",
297→          { objectId },
298→        );
299→        backendNodeId = node.backendNodeId as Protocol.DOM.BackendNodeId;
300→      } catch {
301→        backendNodeId = undefined;
302→      }
303→
304→      const highlightConfig: Protocol.Overlay.HighlightConfig = {
305→        showInfo: false,
306→        showStyles: false,
307→        showRulers: false,
308→        showExtensionLines: false,
309→        borderColor,
310→        contentColor,
311→      } as Protocol.Overlay.HighlightConfig;
312→
313→      const highlightOnce = async () => {
314→        await session.send<never>("Overlay.highlightNode", {
315→          ...(backendNodeId ? { backendNodeId } : { objectId }),
316→          highlightConfig,
317→        });
318→      };
319→
320→      // Initial draw
321→      await highlightOnce();
322→
323→      // Keep alive until duration elapses to resist overlay clears on mouse move/repaints
324→      if (duration > 0) {
325→        const start = Date.now();
326→        const tick = Math.min(300, Math.max(100, Math.floor(duration / 50)));
327→        while (Date.now() - start < duration) {
328→          await new Promise((r) => setTimeout(r, tick));
329→          try {
330→            await highlightOnce();
331→          } catch {
332→            // ignore transient errors
333→          }
334→        }
335→        await session.send<never>("Overlay.hideHighlight").catch(() => {});
336→      }
337→    } finally {
338→      // Releasing objectId should not affect highlight when using backendNodeId.
339→      await session
340→        .send<never>("Runtime.releaseObject", { objectId })
341→        .catch(() => {});
342→    }
343→  }
