377→  /**
378→   * Click the element at its visual center.
379→   * Steps:
380→   *  1) Resolve selector to { objectId } in the frame world.
381→   *  2) Scroll into view via `DOM.scrollIntoViewIfNeeded({ objectId })`.
382→   *  3) Read geometry via `DOM.getBoxModel({ objectId })` → compute a center point.
383→   *  4) Synthesize mouse press + release via `Input.dispatchMouseEvent`.
384→   */
385→  async click(options?: {
386→    button?: MouseButton;
387→    clickCount?: number;
388→  }): Promise<void> {
389→    const session = this.frame.session;
390→    const { objectId } = await this.resolveNode();
391→
392→    const button = options?.button ?? "left";
393→    const clickCount = options?.clickCount ?? 1;
394→
395→    try {
396→      // Scroll into view using objectId (avoids frontend nodeId dependence)
397→      await session.send("DOM.scrollIntoViewIfNeeded", { objectId });
398→
399→      // Get geometry using objectId
400→      const box = await session.send<Protocol.DOM.GetBoxModelResponse>(
401→        "DOM.getBoxModel",
402→        { objectId },
403→      );
404→      if (!box.model) throw new ElementNotVisibleError(this.selector);
405→      const { cx, cy } = this.centerFromBoxContent(box.model.content);
406→
407→      // Dispatch click events in a pipelined burst to reduce inter-click delay
408→      // from network/CPU jitter between round trips.
409→      const dispatches: Array<Promise<unknown>> = [];
410→      dispatches.push(
411→        session.send<never>("Input.dispatchMouseEvent", {
412→          type: "mouseMoved",
413→          x: cx,
414→          y: cy,
415→          button: "none",
416→        } as Protocol.Input.DispatchMouseEventRequest),
417→      );
418→
419→      for (let i = 1; i <= clickCount; i++) {
420→        dispatches.push(
421→          session.send<never>("Input.dispatchMouseEvent", {
422→            type: "mousePressed",
423→            x: cx,
424→            y: cy,
425→            button,
426→            clickCount: i,
427→          } as Protocol.Input.DispatchMouseEventRequest),
428→        );
429→        dispatches.push(
430→          session.send<never>("Input.dispatchMouseEvent", {
431→            type: "mouseReleased",
432→            x: cx,
433→            y: cy,
434→            button,
435→            clickCount: i,
436→          } as Protocol.Input.DispatchMouseEventRequest),
437→        );
438→      }
439→      await Promise.all(dispatches);
440→    } finally {
441→      // release the element handle
442→      try {
443→        await session.send<never>("Runtime.releaseObject", { objectId });
444→      } catch {
445→        // If the context navigated or was destroyed (e.g., link opens new tab),
446→        // releaseObject may fail with -32000. Ignore as best-effort cleanup.
447→      }
448→    }
449→  }
