 28→  public static parseSelector(raw: string): SelectorQuery {
 29→    const trimmed = raw.trim();
 30→
 31→    const isText = /^text=/i.test(trimmed);
 32→    const looksLikeXPath =
 33→      /^xpath=/i.test(trimmed) ||
 34→      trimmed.startsWith("/") ||
 35→      trimmed.startsWith("(");
 36→    const isCssPrefixed = /^css=/i.test(trimmed);
 37→
 38→    if (isText) {
 39→      let value = trimmed.replace(/^text=/i, "").trim();
 40→      if (
 41→        (value.startsWith('"') && value.endsWith('"')) ||
 42→        (value.startsWith("'") && value.endsWith("'"))
 43→      ) {
 44→        value = value.slice(1, -1);
 45→      }
 46→      return { kind: "text", value };
 47→    }
 48→
 49→    if (looksLikeXPath) {
 50→      const value = trimmed.replace(/^xpath=/i, "");
 51→      return { kind: "xpath", value };
 52→    }
 53→
 54→    let selector = isCssPrefixed ? trimmed.replace(/^css=/i, "") : trimmed;
 55→    if (selector.includes(">>")) {
 56→      selector = selector
 57→        .split(">>")
 58→        .map((piece) => piece.trim())
 59→        .filter(Boolean)
 60→        .join(" ");
 61→    }
 62→
 63→    return { kind: "css", value: selector };
 64→  }
