 34→/** Attach File objects created from serialized payloads to an <input type="file">. */
 35→export function assignFilePayloadsToInputElement(
 36→  this: Element,
 37→  payloads: SerializedFilePayload[],
 38→): boolean {
 39→  try {
 40→    const input = this as HTMLInputElement;
 41→    if (!input || input.tagName?.toLowerCase() !== "input") return false;
 42→    if ((input.type ?? "").toLowerCase() !== "file") return false;
 43→
 44→    const transfer: DataTransfer | null = (() => {
 45→      try {
 46→        return new DataTransfer();
 47→      } catch {
 48→        return null;
 49→      }
 50→    })();
 51→    if (!transfer) return false;
 52→
 53→    const entries = Array.isArray(payloads) ? payloads : [];
 54→    for (const payload of entries) {
 55→      if (!payload) continue;
 56→      const name = payload.name || "upload.bin";
 57→      const mimeType = payload.mimeType || "application/octet-stream";
 58→      const lastModified =
 59→        typeof payload.lastModified === "number"
 60→          ? payload.lastModified
 61→          : Date.now();
 62→
 63→      const binary = window.atob(payload.base64 ?? "");
 64→      const bytes = new Uint8Array(binary.length);
 65→      for (let i = 0; i < binary.length; i += 1) {
 66→        bytes[i] = binary.charCodeAt(i);
 67→      }
 68→      const blob = new Blob([bytes], { type: mimeType });
 69→      const file = new File([blob], name, { type: mimeType, lastModified });
 70→      transfer.items.add(file);
 71→    }
 72→
 73→    input.files = transfer.files;
 74→    input.dispatchEvent(new Event("input", { bubbles: true }));
 75→    input.dispatchEvent(new Event("change", { bubbles: true }));
 76→    return true;
 77→  } catch {
 78→    return false;
 79→  }
 80→}
