106→export function scrollElementToPercent(
107→  this: Element,
108→  percent: number | string,
109→): boolean {
110→  const normalize = (value: unknown): number => {
111→    if (typeof value === "number" && Number.isFinite(value)) return value;
112→    const str = String(value ?? "").trim();
113→    if (!str) return 0;
114→    const numeric = parseFloat(str.replace("%", ""));
115→    if (Number.isNaN(numeric) || !Number.isFinite(numeric)) return 0;
116→    return numeric;
117→  };
118→
119→  try {
120→    const pct = Math.max(0, Math.min(normalize(percent), 100));
121→    const element = this as HTMLElement;
122→    const tag = element.tagName?.toLowerCase() ?? "";
123→
124→    const scrollWindow = tag === "html" || tag === "body";
125→    if (scrollWindow) {
126→      const root =
127→        element.ownerDocument?.scrollingElement ||
128→        element.ownerDocument?.documentElement ||
129→        element.ownerDocument?.body ||
130→        document.scrollingElement ||
131→        document.documentElement ||
132→        document.body;
133→      const scrollHeight =
134→        root?.scrollHeight ?? document.body.scrollHeight ?? 0;
135→      const viewportHeight =
136→        element.ownerDocument?.defaultView?.innerHeight ?? window.innerHeight;
137→      const maxTop = Math.max(0, scrollHeight - viewportHeight);
138→      const top = maxTop * (pct / 100);
139→      element.ownerDocument?.defaultView?.scrollTo({
140→        top,
141→        left:
142→          element.ownerDocument?.defaultView?.scrollX ?? window.scrollX ?? 0,
143→        behavior: "smooth",
144→      });
145→      return true;
146→    }
147→
148→    const scrollHeight = element.scrollHeight ?? 0;
149→    const clientHeight = element.clientHeight ?? 0;
150→    const maxTop = Math.max(0, scrollHeight - clientHeight);
151→    const top = maxTop * (pct / 100);
152→    element.scrollTo({
153→      top,
154→      left: element.scrollLeft ?? 0,
155→      behavior: "smooth",
156→    });
157→    return true;
158→  } catch {
159→    return false;
160→  }
161→}
