189→export function prepareElementForTyping(this: Element): boolean {
190→  try {
191→    const element = this as HTMLElement;
192→    if (!element.isConnected) return false;
193→
194→    const doc = element.ownerDocument || document;
195→    const win = doc.defaultView || window;
196→
197→    try {
198→      if (typeof element.focus === "function") {
199→        element.focus();
200→      }
201→    } catch {
202→      /* ignore */
203→    }
204→
205→    if (
206→      element instanceof win.HTMLInputElement ||
207→      element instanceof win.HTMLTextAreaElement
208→    ) {
209→      try {
210→        if (typeof element.select === "function") {
211→          element.select();
212→          return true;
213→        }
214→      } catch {
215→        /* ignore */
216→      }
217→
218→      try {
219→        const length = (element.value ?? "").length;
220→        if (typeof element.setSelectionRange === "function") {
221→          element.setSelectionRange(0, length);
222→          return true;
223→        }
224→      } catch {
225→        /* ignore */
226→      }
227→
228→      return true;
229→    }
230→
231→    if (element.isContentEditable) {
232→      const selection = doc.getSelection?.();
233→      const range = doc.createRange?.();
234→      if (selection && range) {
235→        try {
236→          range.selectNodeContents(element);
237→          selection.removeAllRanges();
238→          selection.addRange(range);
239→        } catch {
240→          /* ignore */
241→        }
242→      }
243→      return true;
244→    }
245→
246→    return false;
247→  } catch {
248→    return false;
249→  }
250→}
