252→export function fillElementValue(
253→  this: Element,
254→  rawValue: string,
255→): FillElementResult {
256→  const element = this as HTMLElement;
257→  if (!element.isConnected) {
258→    return { status: "error", reason: "notconnected" };
259→  }
260→
261→  const doc = element.ownerDocument || document;
262→  const win = doc.defaultView || window;
263→  let fallbackValue = rawValue ?? "";
264→
265→  try {
266→    const dispatchInputAndChange = (eventValue: string): void => {
267→      let inputEvent: Event;
268→      if (typeof win.InputEvent === "function") {
269→        try {
270→          inputEvent = new win.InputEvent("input", {
271→            bubbles: true,
272→            composed: true,
273→            data: eventValue,
274→            inputType: "insertText",
275→          });
276→        } catch {
277→          inputEvent = new win.Event("input", {
278→            bubbles: true,
279→            composed: true,
280→          });
281→        }
282→      } else {
283→        inputEvent = new win.Event("input", { bubbles: true, composed: true });
284→      }
285→
286→      element.dispatchEvent(inputEvent);
287→
288→      const changeEvent = new win.Event("change", { bubbles: true });
289→      element.dispatchEvent(changeEvent);
290→    };
291→
292→    if (element instanceof win.HTMLInputElement) {
293→      const type = (element.type || "").toLowerCase();
294→
295→      if (!inputTypesToTypeInto.has(type) && !inputTypesToSetValue.has(type)) {
296→        return { status: "error", reason: `unsupported-input-type:${type}` };
297→      }
298→
299→      let valueForTyping = rawValue;
300→
301→      if (type === "number") {
302→        const trimmed = rawValue.trim();
303→        if (trimmed !== "" && Number.isNaN(Number(trimmed))) {
304→          return { status: "error", reason: "invalid-number-value" };
305→        }
306→        valueForTyping = trimmed;
307→      }
308→
309→      fallbackValue = valueForTyping;
310→
311→      if (inputTypesToSetValue.has(type)) {
312→        const trimmed = rawValue.trim();
313→        fallbackValue = trimmed;
314→        prepareElementForTyping.call(element);
315→
316→        const prototype = win.HTMLInputElement.prototype;
317→        const descriptor = Object.getOwnPropertyDescriptor(prototype, "value");
318→        const nativeSetter = descriptor?.set;
319→
320→        if (typeof nativeSetter === "function") {
321→          nativeSetter.call(element, trimmed);
322→        } else {
323→          element.value = trimmed;
324→        }
325→
326→        const tracker = (
327→          element as unknown as {
328→            _valueTracker?: { setValue?: (next: string) => void };
329→          }
330→        )._valueTracker;
331→        tracker?.setValue?.(trimmed);
332→
333→        if (element.value !== trimmed) {
334→          return { status: "error", reason: "malformed-value" };
335→        }
336→
337→        dispatchInputAndChange(trimmed);
338→        return { status: "done" };
339→      }
340→
341→      prepareElementForTyping.call(element);
342→      return { status: "needsinput", value: valueForTyping };
343→    }
344→
345→    if (element instanceof win.HTMLTextAreaElement) {
346→      prepareElementForTyping.call(element);
347→      fallbackValue = rawValue;
348→      return { status: "needsinput", value: rawValue };
349→    }
350→
351→    if (element instanceof win.HTMLSelectElement) {
352→      // Select elements use setInputFiles/selectOption instead.
353→      return { status: "error", reason: "unsupported-element" };
354→    }
355→
356→    if (element.isContentEditable) {
357→      prepareElementForTyping.call(element);
358→      fallbackValue = rawValue;
359→      return { status: "needsinput", value: rawValue };
360→    }
361→
362→    return { status: "error", reason: "unsupported-element" };
363→  } catch (error) {
364→    let reason = "exception";
365→    if (error && typeof error === "object") {
366→      const message = (error as { message?: unknown }).message;
367→      if (typeof message === "string" && message.trim().length > 0) {
368→        reason = `exception:${message}`;
369→      }
370→    }
371→    return { status: "needsinput", value: fallbackValue, reason };
372→  }
373→}
