  9→const collectCssMatches = (selector: string, limit: number): Element[] => {
 10→  if (!selector) return [];
 11→  const seenRoots = new WeakSet<Node>();
 12→  const seenElements = new Set<Element>();
 13→  const results: Element[] = [];
 14→  const queue: Array<Document | ShadowRoot> = [document];
 15→
 16→  const visit = (root: Document | ShadowRoot): void => {
 17→    if (!root || seenRoots.has(root) || results.length >= limit) return;
 18→    seenRoots.add(root);
 19→
 20→    try {
 21→      const matches = root.querySelectorAll(selector);
 22→      for (const element of matches) {
 23→        if (seenElements.has(element)) continue;
 24→        seenElements.add(element);
 25→        results.push(element);
 26→        if (results.length >= limit) return;
 27→      }
 28→    } catch {
 29→      // ignore querySelectorAll issues
 30→    }
 31→
 32→    try {
 33→      const ownerDocument =
 34→        root instanceof Document
 35→          ? root
 36→          : (root.host?.ownerDocument ?? document);
 37→      const walker = ownerDocument.createTreeWalker(
 38→        root,
 39→        NodeFilter.SHOW_ELEMENT,
 40→      );
 41→      let node: Node | null;
 42→      while ((node = walker.nextNode())) {
 43→        if (!(node instanceof Element)) continue;
 44→        const open = node.shadowRoot;
 45→        if (open) queue.push(open);
 46→      }
 47→    } catch {
 48→      // ignore traversal issues
 49→    }
 50→  };
 51→
 52→  while (queue.length && results.length < limit) {
 53→    const next = queue.shift();
 54→    if (next) visit(next);
 55→  }
 56→
 57→  return results;
 58→};
