 60→export function resolveCssSelector(
 61→  selectorRaw: string,
 62→  targetIndexRaw?: number,
 63→): Element | null {
 64→  const selector = String(selectorRaw ?? "").trim();
 65→  if (!selector) return null;
 66→
 67→  const targetIndex = parseTargetIndex(targetIndexRaw);
 68→  const matches = collectCssMatches(selector, targetIndex + 1);
 69→  return matches[targetIndex] ?? null;
 70→}
