 72→export function resolveCssSelectorPierce(
 73→  selectorRaw: string,
 74→  targetIndexRaw?: number,
 75→): Element | null {
 76→  const selector = String(selectorRaw ?? "").trim();
 77→  if (!selector) return null;
 78→
 79→  const targetIndex = parseTargetIndex(targetIndexRaw);
 80→  const backdoor = window.__stagehandV3__;
 81→  if (!backdoor || typeof backdoor.getClosedRoot !== "function") {
 82→    const matches = collectCssMatches(selector, targetIndex + 1);
 83→    return matches[targetIndex] ?? null;
 84→  }
 85→
 86→  const getClosedRoot: (host: Element) => ShadowRoot | null = (
 87→    host: Element,
 88→  ) => {
 89→    try {
 90→      return backdoor.getClosedRoot(host) ?? null;
 91→    } catch {
 92→      return null;
 93→    }
 94→  };
 95→
 96→  const seenRoots = new WeakSet<Node>();
 97→  const seenElements = new Set<Element>();
 98→  const results: Element[] = [];
 99→  const queue: Array<Document | ShadowRoot> = [document];
100→
101→  const visit = (root: Document | ShadowRoot): void => {
102→    if (!root || seenRoots.has(root) || results.length >= targetIndex + 1)
103→      return;
104→    seenRoots.add(root);
105→
106→    try {
107→      const matches = root.querySelectorAll(selector);
108→      for (const element of matches) {
109→        if (seenElements.has(element)) continue;
110→        seenElements.add(element);
111→        results.push(element);
112→        if (results.length >= targetIndex + 1) return;
113→      }
114→    } catch {
115→      // ignore query errors
116→    }
117→
118→    try {
119→      const ownerDocument =
120→        root instanceof Document
121→          ? root
122→          : (root.host?.ownerDocument ?? document);
123→      const walker = ownerDocument.createTreeWalker(
124→        root,
125→        NodeFilter.SHOW_ELEMENT,
126→      );
127→      let node: Node | null;
128→      while ((node = walker.nextNode())) {
129→        if (!(node instanceof Element)) continue;
130→        const open = node.shadowRoot;
131→        if (open) queue.push(open);
132→        const closed = getClosedRoot(node);
133→        if (closed) queue.push(closed);
134→      }
135→    } catch {
136→      // ignore traversal issues
137→    }
138→  };
139→
140→  while (queue.length && results.length < targetIndex + 1) {
141→    const next = queue.shift();
142→    if (next) visit(next);
143→  }
144→
145→  return results[targetIndex] ?? null;
