170→  const shouldSkip = (node: Element | null | undefined): boolean => {
171→    if (!node) return false;
172→    const tag = node.tagName?.toUpperCase() ?? "";
173→    return skipTags.has(tag);
174→  };
175→
176→  const extractText = (node: Element): string => {
177→    try {
178→      if (shouldSkip(node)) return "";
179→      const inner = (node as HTMLElement).innerText;
180→      if (typeof inner === "string" && inner.trim()) return inner.trim();
181→    } catch {
182→      // ignore
183→    }
184→    try {
185→      const text = node.textContent;
186→      if (typeof text === "string") return text.trim();
187→    } catch {
188→      // ignore
189→    }
190→    return "";
191→  };
192→
193→  const matches = (node: Element): boolean => {
194→    const text = extractText(node);
195→    return !!text && text.toLowerCase().includes(needleLc);
196→  };
197→
198→  const backdoor = window.__stagehandV3__;
199→  const getClosedRoot: (host: Element) => ShadowRoot | null =
200→    backdoor && typeof backdoor.getClosedRoot === "function"
201→      ? (host: Element): ShadowRoot | null => {
202→          try {
203→            return backdoor.getClosedRoot(host) ?? null;
204→          } catch {
205→            return null;
206→          }
207→        }
208→      : (host: Element): ShadowRoot | null => {
209→          void host;
210→          return null;
211→        };
212→
213→  const seen = new WeakSet<Node>();
214→  const queue: Node[] = [];
215→  const matchesList: Array<{
216→    element: Element;
217→    tag: string;
218→    id: string;
219→    className: string;
220→    text: string;
221→  }> = [];
222→
223→  const enqueue = (node: Node | null | undefined) => {
224→    if (!node || seen.has(node)) return;
225→    seen.add(node);
226→    queue.push(node);
227→  };
228→
229→  const walkerFor = (root: Node): TreeWalker | null => {
230→    try {
231→      const doc =
232→        root instanceof Document
233→          ? root
234→          : ((root as Element)?.ownerDocument ?? document);
235→      return doc.createTreeWalker(root, NodeFilter.SHOW_ELEMENT);
236→    } catch {
237→      return null;
238→    }
239→  };
240→
241→  enqueue(document);
242→
243→  while (queue.length) {
244→    const root = queue.shift();
245→    if (!root) continue;
246→
247→    if (root instanceof Element && matches(root)) {
248→      matchesList.push({
249→        element: root,
250→        tag: root.tagName ?? "",
251→        id: root.id ?? "",
252→        className: (root as HTMLElement).className ?? "",
253→        text: extractText(root),
254→      });
255→    }
256→
257→    const walker = walkerFor(root);
258→    if (!walker) continue;
259→
260→    let node: Node | null;
261→    while ((node = walker.nextNode())) {
262→      if (!(node instanceof Element)) continue;
263→
264→      if (matches(node)) {
265→        matchesList.push({
266→          element: node,
267→          tag: node.tagName ?? "",
268→          id: node.id ?? "",
269→          className: (node as HTMLElement).className ?? "",
270→          text: extractText(node),
271→        });
272→      }
273→
274→      const open = node.shadowRoot;
275→      if (open) enqueue(open);
276→
277→      const closed = getClosedRoot(node);
278→      if (closed) enqueue(closed);
279→    }
280→  }
281→
282→  const innermost: typeof matchesList = [];
283→  for (const item of matchesList) {
284→    const el = item.element;
285→    let skip = false;
286→    for (const other of matchesList) {
287→      if (item === other) continue;
288→      try {
289→        if (el.contains(other.element)) {
290→          skip = true;
291→          break;
292→        }
293→      } catch {
294→        // ignore containment errors
295→      }
296→    }
297→    if (!skip) {
298→      innermost.push(item);
299→    }
300→  }
301→
302→  const target = innermost[targetIndex];
303→  return target?.element ?? null;
304→}
