  5→/**
  6→ * Build the absolute XPath for a node by walking through every iframe host
  7→ * we've traversed so far followed by the leaf backend node.
  8→ */
  9→export async function buildAbsoluteXPathFromChain(
 10→  chain: Array<{
 11→    parentSession: CDPSessionLike;
 12→    iframeBackendNodeId: number;
 13→  }>,
 14→  leafSession: CDPSessionLike,
 15→  leafBackendNodeId: number,
 16→): Promise<string | null> {
 17→  let prefix = "";
 18→  for (const step of chain) {
 19→    const xp = await absoluteXPathForBackendNode(
 20→      step.parentSession,
 21→      step.iframeBackendNodeId,
 22→    );
 23→    if (!xp) continue;
 24→    prefix = prefix ? prefixXPath(prefix, xp) : normalizeXPath(xp);
 25→  }
 26→  const leaf = await absoluteXPathForBackendNode(
 27→    leafSession,
 28→    leafBackendNodeId,
 29→  );
 30→  if (!leaf) return prefix || "/";
 31→  return prefix ? prefixXPath(prefix, leaf) : normalizeXPath(leaf);
 32→}
