 34→/**
 35→ * Resolve a backend node to an absolute XPath within the provided session.
 36→ * The CDP Runtime is used so we can invoke a small helper that walks the DOM.
 37→ */
 38→export async function absoluteXPathForBackendNode(
 39→  session: CDPSessionLike,
 40→  backendNodeId: number,
 41→): Promise<string | null> {
 42→  try {
 43→    const { object } = await session.send<{ object: { objectId?: string } }>(
 44→      "DOM.resolveNode",
 45→      { backendNodeId },
 46→    );
 47→    const objectId = object?.objectId;
 48→    if (!objectId) return null;
 49→
 50→    const { result } = await session.send<{ result: { value?: string } }>(
 51→      "Runtime.callFunctionOn",
 52→      {
 53→        objectId,
 54→        functionDeclaration: a11yScriptSources.nodeToAbsoluteXPath,
 55→        returnByValue: true,
 56→      },
 57→    );
 58→    await session.send("Runtime.releaseObject", { objectId }).catch(() => {});
 59→    return typeof result?.value === "string" && result.value
 60→      ? result.value
 61→      : null;
 62→  } catch {
 63→    return null;
 64→  }
 65→}
