 67→/**
 68→ * Prefix `child` XPath with an absolute iframe path `parentAbs`.
 69→ * Handles root slashes and shadow hops (“//”) cleanly.
 70→ */
 71→export function prefixXPath(parentAbs: string, child: string): string {
 72→  const p = parentAbs === "/" ? "" : parentAbs.replace(/\/$/, "");
 73→  if (!child || child === "/") return p || "/";
 74→  if (child.startsWith("//"))
 75→    return p ? `${p}//${child.slice(2)}` : `//${child.slice(2)}`;
 76→  const c = child.replace(/^\//, "");
 77→  return p ? `${p}/${c}` : `/${c}`;
 78→}
