 80→/** Normalize an XPath: strip `xpath=`, ensure leading '/', remove trailing '/'. */
 81→export function normalizeXPath(x?: string): string {
 82→  if (!x) return "";
 83→  let s = x.trim().replace(/^xpath=/i, "");
 84→  if (!s.startsWith("/")) s = "/" + s;
 85→  if (s.length > 1 && s.endsWith("/")) s = s.slice(0, -1);
 86→  return s;
 87→}
