 89→/** Build per-sibling XPath steps for DOM traversal. */
 90→export function buildChildXPathSegments(kids: Protocol.DOM.Node[]): string[] {
 91→  const segs: string[] = [];
 92→  const ctr: Record<string, number> = {};
 93→  for (const child of kids) {
 94→    const tag = String(child.nodeName).toLowerCase();
 95→    const key = `${child.nodeType}:${tag}`;
 96→    const idx = (ctr[key] = (ctr[key] ?? 0) + 1);
 97→    if (child.nodeType === 3) {
 98→      segs.push(`text()[${idx}]`);
 99→    } else if (child.nodeType === 8) {
100→      segs.push(`comment()[${idx}]`);
101→    } else {
102→      segs.push(
103→        tag.includes(":") ? `*[name()='${tag}'][${idx}]` : `${tag}[${idx}]`,
104→      );
105→    }
106→  }
107→  return segs;
108→}
