110→/** Join two XPath fragments while preserving special shadow-root hops. */
111→export function joinXPath(base: string, step: string): string {
112→  if (step === "//") {
113→    if (!base || base === "/") return "//";
114→    return base.endsWith("/") ? `${base}/` : `${base}//`;
115→  }
116→  if (!base || base === "/") return step ? `/${step}` : "/";
117→  if (base.endsWith("//")) return `${base}${step}`;
118→  if (!step) return base;
119→  return `${base}/${step}`;
120→}
