 49→export function nodeToAbsoluteXPath(this: Node | null | undefined): string {
 50→  const compute = (node: Node | null | undefined): string => {
 51→    try {
 52→      const sibIndex = (n: Node | null | undefined): number => {
 53→        if (!n || !n.parentNode) return 1;
 54→        let i = 1;
 55→        const targetKey = `${n.nodeType}:${(n.nodeName || "").toLowerCase()}`;
 56→        for (let p = n.previousSibling; p; p = p.previousSibling) {
 57→          const key = `${p.nodeType}:${(p.nodeName || "").toLowerCase()}`;
 58→          if (key === targetKey) i += 1;
 59→        }
 60→        return i;
 61→      };
 62→
 63→      const step = (n: Node | null | undefined): string => {
 64→        if (!n) return "";
 65→        if (n.nodeType === Node.DOCUMENT_NODE) return "";
 66→        if (n.nodeType === Node.DOCUMENT_FRAGMENT_NODE) return "//";
