 94→          out = out
 95→            ? out.endsWith("/")
 96→              ? `${out}${part}`
 97→              : `${out}/${part}`
 98→            : `/${part}`;
 99→        }
100→      }
101→      return out || "/";
102→    } catch {
103→      return "/";
104→    }
105→  };
106→
107→  return compute(this);
108→}
