  1→export type XPathPredicate =
  2→  | { type: "index"; index: number }
  3→  | { type: "attrEquals"; name: string; value: string; normalize?: boolean }
  4→  | { type: "attrExists"; name: string }
  5→  | {
  6→      type: "attrContains";
  7→      name: string;
  8→      value: string;
  9→      normalize?: boolean;
 10→    }
 11→  | {
 12→      type: "attrStartsWith";
 13→      name: string;
 14→      value: string;
 15→      normalize?: boolean;
 16→    }
 17→  | { type: "textEquals"; value: string; normalize?: boolean }
 18→  | { type: "textContains"; value: string; normalize?: boolean }
 19→  | { type: "and"; predicates: XPathPredicate[] }
 20→  | { type: "or"; predicates: XPathPredicate[] }
 21→  | { type: "not"; predicate: XPathPredicate };
 22→
 23→export interface XPathStep {
 24→  axis: "child" | "desc";
 25→  tag: string;
 26→  predicates: XPathPredicate[];
 27→}
 28→
 29→/**
 30→ * Parse an XPath expression into a list of traversal steps.
 31→ *
 32→ * This is a subset parser designed for composed DOM traversal (including
 33→ * shadow roots). It intentionally does not implement the full XPath spec.
 34→ *
 35→ * Supported:
 36→ *  - Child (`/`) and descendant (`//`) axes
 37→ *  - Tag names and wildcard (`*`)
 38→ *  - Positional indices (`[n]`)
 39→ *  - Attribute equality predicates (`[@attr='value']`, `[@attr="value"]`)
 40→ *  - Attribute existence (`[@attr]`)
 41→ *  - Attribute contains/starts-with (`contains(@attr,'v')`, `starts-with(@attr,'v')`)
 42→ *  - Text equality/contains (`[text()='v']`, `[contains(text(),'v')]`, `[.='v']`)
 43→ *  - normalize-space on text/attributes (`[normalize-space(text())='v']`)
 44→ *  - Basic boolean predicates (`and`, `or`, `not(...)`)
 45→ *  - Multiple predicates per step (`[@class='foo'][2]`)
 46→ *  - Optional `xpath=` prefix
 47→ *
 48→ * Not supported:
 49→ *  - Position functions (`[position() > n]`, `[last()]`)
 50→ *  - Axes beyond child/descendant (`ancestor::`, `parent::`, `self::`,
 51→ *    `preceding-sibling::`, `following-sibling::`)
 52→ *  - Union operator (`|`)
 53→ *  - Grouped expressions (`(//div)[n]`)
 54→ *
 55→ * Unsupported predicates are silently ignored — the step still matches
 56→ * by tag name, but the unrecognized predicate has no filtering effect.
 57→ */
 58→export function parseXPathSteps(input: string): XPathStep[] {
 59→  const path = String(input || "")
 60→    .trim()
 61→    .replace(/^xpath=/i, "");
 62→  if (!path) return [];
 63→
 64→  const steps: XPathStep[] = [];
 65→  let i = 0;
 66→
 67→  while (i < path.length) {
 68→    let axis: "child" | "desc" = "child";
 69→    if (path.startsWith("//", i)) {
 70→      axis = "desc";
 71→      i += 2;
 72→    } else if (path[i] === "/") {
 73→      axis = "child";
 74→      i += 1;
 75→    }
 76→
 77→    const start = i;
 78→    let bracketDepth = 0;
 79→    let quote: string | null = null;
 80→    while (i < path.length) {
 81→      const ch = path[i];
 82→      if (quote) {
 83→        if (ch === quote) quote = null;
 84→      } else if (ch === "'" || ch === '"') {
 85→        quote = ch;
 86→      } else if (ch === "[") {
 87→        bracketDepth++;
 88→      } else if (ch === "]") {
 89→        bracketDepth--;
 90→      } else if (ch === "/" && bracketDepth === 0) {
 91→        break;
 92→      }
 93→      i += 1;
 94→    }
 95→    const rawStep = path.slice(start, i).trim();
 96→    if (!rawStep) continue;
 97→
 98→    const { tag, predicates } = parseStep(rawStep);
 99→    steps.push({ axis, tag, predicates });
100→  }
101→
102→  return steps;
103→}
104→
105→/**
106→ * Extract predicate contents from a string like `[@attr='val'][2]`.
107→ * Handles `]` inside quoted attribute values (e.g. `[@title='a[0]']`).
108→ */
109→function extractPredicates(str: string): string[] {
110→  const results: string[] = [];
111→  let i = 0;
112→  while (i < str.length) {
113→    if (str[i] !== "[") {
114→      i++;
115→      continue;
116→    }
117→    i++; // skip opening [
118→    const start = i;
119→    let quote: string | null = null;
120→    while (i < str.length) {
121→      const ch = str[i];
122→      if (quote) {
123→        if (ch === quote) quote = null;
124→      } else if (ch === "'" || ch === '"') {
125→        quote = ch;
126→      } else if (ch === "]") {
127→        break;
128→      }
129→      i++;
130→    }
131→    results.push(str.slice(start, i).trim());
132→    i++; // skip closing ]
133→  }
134→  return results;
135→}
136→
137→function parseStep(raw: string): {
138→  tag: string;
139→  predicates: XPathPredicate[];
140→} {
141→  const bracketPos = raw.indexOf("[");
142→  if (bracketPos === -1) {
143→    const tag = raw === "" ? "*" : raw.toLowerCase();
144→    return { tag, predicates: [] };
145→  }
146→
147→  const tagPart = raw.slice(0, bracketPos).trim();
148→  const tag = tagPart === "" ? "*" : tagPart.toLowerCase();
149→  const predicateStr = raw.slice(bracketPos);
150→
151→  const predicates: XPathPredicate[] = [];
152→
153→  for (const inner of extractPredicates(predicateStr)) {
154→    const parsed = parsePredicateExpression(inner);
155→    if (parsed) predicates.push(parsed);
156→  }
157→
158→  return { tag, predicates };
159→}
160→
161→function parsePredicateExpression(input: string): XPathPredicate | null {
162→  const trimmed = input.trim();
163→  if (!trimmed) return null;
164→
165→  const orParts = splitTopLevel(trimmed, "or");
166→  if (orParts.length > 1) {
167→    const preds = orParts
168→      .map((part) => parsePredicateExpression(part))
169→      .filter(Boolean) as XPathPredicate[];
170→    if (preds.length !== orParts.length) return null;
171→    return { type: "or", predicates: preds };
172→  }
173→
174→  const andParts = splitTopLevel(trimmed, "and");
175→  if (andParts.length > 1) {
176→    const preds = andParts
177→      .map((part) => parsePredicateExpression(part))
178→      .filter(Boolean) as XPathPredicate[];
179→    if (preds.length !== andParts.length) return null;
180→    return { type: "and", predicates: preds };
181→  }
182→
183→  const notInner = unwrapFunctionCall(trimmed, "not");
